function [] = EMC_ctf_refine_from_star(star_file_path, stack_file_path, ...
    reference_volume_path, output_star_path, varargin)
% EMC_ctf_refine_from_star - Standalone CTF refinement from star file + external reference.
%
% Refines per-tilt defocus, astigmatism, and per-particle Z offsets using
% ADAM-based optimization. Reference projections are generated by rotating
% a 3D reference volume and projecting along Z.
%
% INPUTS:
%   star_file_path        - Input star file (30-column, from BH_to_cisTEM_mapBack)
%   stack_file_path       - Particle stack MRC file
%   reference_volume_path - 3D reference volume MRC file
%   output_star_path      - Output refined star file path
%   varargin              - Name-value option pairs:
%       'defocus_search_range'     - Defocus search range in Angstroms (default: 5000)
%       'maximum_iterations'       - Max ADAM iterations (default: 15)
%       'upsample_factor'          - Fourier upsampling factor (default: 8)
%       'upsample_window'          - Half-width of upsampling window (default: 8)
%       'lowpass_cutoff'           - Lowpass cutoff in Angstroms (default: 10)
%       'warmup_iterations'        - Warmup iterations (default: 3)
%       'astigmatism_angle_range'  - Max astigmatism angle change in radians (default: pi/4)
%       'z_offset_bound_factor'    - Z offset bound multiplier (default: 5)
%       'n_debug_particles'        - Particles for angle convention debug (default: 20)
%       'skip_debug'               - Skip angle convention debug (default: false)

%% ===== Stage A: Parse inputs and star file =====

% Parse name-value options
opts = parse_options(varargin);

fprintf('=== EMC_ctf_refine_from_star ===\n');
fprintf('  Star file:     %s\n', star_file_path);
fprintf('  Stack file:    %s\n', stack_file_path);
fprintf('  Reference vol: %s\n', reference_volume_path);
fprintf('  Output:        %s\n', output_star_path);

[particles, header_lines] = parse_star_file(star_file_path);
n_total_particles = length(particles);
fprintf('  Parsed %d particles from star file\n', n_total_particles);

%% ===== Stage B: Load stack + reference volume =====

stack_mrc = MRCImage(stack_file_path, 0);
stack_header = getHeader(stack_mrc);
tile_size = [stack_header.nX, stack_header.nY];
fprintf('  Stack tile size: [%d, %d], %d slices\n', tile_size(1), tile_size(2), stack_header.nZ);

% FIXME: Add half-set reference support if this process works
ref_vol = gpuArray(single(OPEN_IMG('single', reference_volume_path)));
ref_vol_size = size(ref_vol);
fprintf('  Reference volume size: [%d, %d, %d]\n', ref_vol_size(1), ref_vol_size(2), ref_vol_size(3));

% Create interpolator for reference volume
ref_interp = interpolator(ref_vol, [0,0,0], [0,0,0], 'SPIDER', 'inv', 'C1');

%% ===== Stage C: Euler angle convention debug =====

if ~opts.skip_debug
  best_permutation = run_angle_convention_debug(particles, stack_mrc, tile_size, ...
      ref_interp, ref_vol_size, opts.n_debug_particles);
else
  % Default: use negated angles (original e1,e2,e3 from rotm2eul)
  best_permutation = 'B';
  fprintf('Skipping angle convention debug, using default permutation B [-psi,-theta,-phi]\n');
end

%% ===== Stage D: Group particles by tilt, sort by ascending |tilt_angle| =====

all_tilt_names = {particles.original_image_filename};
[unique_tilt_names, ~, tilt_group_indices] = unique(all_tilt_names);
n_tilt_groups = length(unique_tilt_names);

% Get tilt angle per group from the first particle in each group
tilt_angles_per_group = zeros(n_tilt_groups, 1);
for group_index = 1:n_tilt_groups
  members = find(tilt_group_indices == group_index);
  tilt_angles_per_group(group_index) = particles(members(1)).tilt_angle;
end
[~, ascending_tilt_order] = sort(abs(tilt_angles_per_group));

fprintf('  %d tilt groups, processing in ascending |tilt| order\n', n_tilt_groups);

%% ===== Stage E: Per-tilt refinement loop =====

% Storage for refined values (indexed by particle order in star file)
refined_defocus_1 = zeros(n_total_particles, 1);
refined_defocus_2 = zeros(n_total_particles, 1);
refined_astigmatism_angle = zeros(n_total_particles, 1);
refined_shift_x = zeros(n_total_particles, 1);
refined_shift_y = zeros(n_total_particles, 1);
refined_scores = zeros(n_total_particles, 1);
refined_occupancy = 100.0 * ones(n_total_particles, 1);

% Tilt-dependent scoring accumulators
baseline_median_score = [];
accumulated_angle_score_pairs = [];

% Get microscope parameters from first particle (constant across stack)
pixel_size_angstroms = particles(1).pixel_size;
voltage_kv = particles(1).voltage_kv;
voltage_volts = voltage_kv * 1e3;
wavelength_angstroms = 12.2643 / sqrt(voltage_volts * (1 + voltage_volts * 0.978466e-6));
cs_mm = particles(1).cs_mm;
amplitude_contrast = particles(1).amplitude_contrast;

for sorted_index = 1:n_tilt_groups
  group_index = ascending_tilt_order(sorted_index);
  current_tilt_name = unique_tilt_names{group_index};
  member_indices = find(tilt_group_indices == group_index);
  n_particles_this_tilt = length(member_indices);
  current_tilt_angle = tilt_angles_per_group(group_index);

  fprintf('  Refining tilt %s (angle %.1f deg, %d particles)...\n', ...
    current_tilt_name, current_tilt_angle, n_particles_this_tilt);

  % Determine consecutive slice range for batch loading
  slice_indices = [particles(member_indices).position_in_stack];
  first_slice = min(slice_indices);
  last_slice = max(slice_indices);

  % Batch-load data tiles from stack
  tilt_data = single(OPEN_IMG('single', stack_mrc, [1,tile_size(1)], [1,tile_size(2)], [first_slice, last_slice], 'keep'));

  % Build data and reference tile cell arrays
  data_tiles = cell(n_particles_this_tilt, 1);
  ref_tiles = cell(n_particles_this_tilt, 1);
  initial_shifts = zeros(n_particles_this_tilt, 2);

  ctf_params_for_tilt = struct();
  ctf_params_for_tilt.defocus_mean = zeros(n_particles_this_tilt, 1);
  ctf_params_for_tilt.half_astigmatism = zeros(n_particles_this_tilt, 1);
  ctf_params_for_tilt.astigmatism_angle = zeros(n_particles_this_tilt, 1);
  ctf_params_for_tilt.pixel_size_angstroms = pixel_size_angstroms;
  ctf_params_for_tilt.wavelength_angstroms = wavelength_angstroms;
  ctf_params_for_tilt.spherical_aberration_mm = cs_mm;
  ctf_params_for_tilt.amplitude_contrast = amplitude_contrast;
  ctf_params_for_tilt.tilt_angle_degrees = current_tilt_angle;

  for particle_index = 1:n_particles_this_tilt
    p = particles(member_indices(particle_index));
    local_slice = p.position_in_stack - first_slice + 1;

    data_tiles{particle_index} = gpuArray(tilt_data(:,:,local_slice));

    % Generate reference projection: rotate volume, project along Z
    angles = apply_best_permutation(p.psi, p.theta, p.phi, best_permutation);
    rotated_vol = ref_interp.interp3d(angles, [0,0,0], 'SPIDER', 'inv', 'C1');
    ref_projection = sum(rotated_vol, 3);
    ref_tiles{particle_index} = center_crop_or_pad(ref_projection, tile_size);

    % Shifts are stored in Angstroms in the star file, convert to pixels
    initial_shifts(particle_index, :) = [p.x_shift / pixel_size_angstroms, ...
                                          p.y_shift / pixel_size_angstroms];

    % CTF params: defocus_mean = (df1+df2)/2, half_astig = (df1-df2)/2
    ctf_params_for_tilt.defocus_mean(particle_index) = (p.defocus_1 + p.defocus_2) / 2;
    ctf_params_for_tilt.half_astigmatism(particle_index) = (p.defocus_1 - p.defocus_2) / 2;
    ctf_params_for_tilt.astigmatism_angle(particle_index) = p.defocus_angle * pi / 180;
  end

  % Clear batch data from CPU
  clear tilt_data;

  % Prepare refinement options
  refinement_options = struct();
  refinement_options.defocus_search_range = opts.defocus_search_range;
  refinement_options.maximum_iterations = opts.maximum_iterations;
  refinement_options.upsample_factor = opts.upsample_factor;
  refinement_options.upsample_window = opts.upsample_window;
  refinement_options.CTFSIZE = tile_size;
  refinement_options.use_phase_correlation = false;
  refinement_options.warmup_iterations = opts.warmup_iterations;
  refinement_options.lowpass_cutoff = opts.lowpass_cutoff;
  refinement_options.astigmatism_angle_range = opts.astigmatism_angle_range;
  refinement_options.z_offset_bound_factor = opts.z_offset_bound_factor;
  refinement_options.peak_search_radius = floor(tile_size / 4);
  refinement_options.maximum_xy_shift = max(floor(tile_size / 4));

  % Run ADAM refinement for this tilt
  tilt_results = EMC_refine_tilt_ctf(data_tiles, ref_tiles, ctf_params_for_tilt, ...
      initial_shifts, refinement_options);

  % Store refined values for each particle
  for particle_index = 1:n_particles_this_tilt
    idx = member_indices(particle_index);
    p = particles(idx);

    % Apply per-tilt defocus offset and per-particle dz
    particle_dz = 0;
    if ~isempty(tilt_results.delta_z) && particle_index <= length(tilt_results.delta_z)
      particle_dz = tilt_results.delta_z(particle_index);
    end
    defocus_correction = tilt_results.delta_defocus_tilt + particle_dz * cosd(current_tilt_angle);

    defocus_mean = (p.defocus_1 + p.defocus_2) / 2;
    half_astig = (p.defocus_1 - p.defocus_2) / 2;

    refined_defocus_1(idx) = defocus_mean + half_astig + ...
        tilt_results.delta_half_astigmatism + defocus_correction;
    refined_defocus_2(idx) = defocus_mean - half_astig - ...
        tilt_results.delta_half_astigmatism + defocus_correction;
    refined_astigmatism_angle(idx) = (p.defocus_angle * pi/180 + tilt_results.delta_astigmatism_angle) * 180 / pi;
    refined_shift_x(idx) = tilt_results.shift_x(particle_index) * pixel_size_angstroms;
    refined_shift_y(idx) = tilt_results.shift_y(particle_index) * pixel_size_angstroms;
    refined_scores(idx) = tilt_results.per_particle_scores(particle_index);
  end

  % Tilt-dependent scoring (cos^alpha model)
  tilt_scores = tilt_results.per_particle_scores;
  if abs(current_tilt_angle) < 10
    baseline_median_score = median(tilt_scores);
    score_threshold = prctile(tilt_scores, 10);
  else
    if ~isempty(baseline_median_score) && ~isempty(accumulated_angle_score_pairs)
      angles_rad = accumulated_angle_score_pairs(:,1) * pi / 180;
      log_ratio = log(accumulated_angle_score_pairs(:,2) / baseline_median_score);
      log_cos = log(cos(angles_rad));
      valid = isfinite(log_ratio) & isfinite(log_cos) & log_cos ~= 0;
      if any(valid)
        alpha_fit = log_ratio(valid) \ log_cos(valid);
      else
        alpha_fit = 1;
      end
      expected_score = baseline_median_score * cosd(current_tilt_angle)^alpha_fit;
      score_threshold = expected_score * 0.3;
    else
      score_threshold = prctile(tilt_scores, 10);
    end
  end

  % Mark particles below threshold with occupancy=0
  for particle_index = 1:n_particles_this_tilt
    idx = member_indices(particle_index);
    if refined_scores(idx) < score_threshold
      refined_occupancy(idx) = 0;
    end
  end

  % Accumulate for scoring model
  kept_scores = tilt_scores(tilt_scores >= score_threshold);
  if ~isempty(kept_scores)
    accumulated_angle_score_pairs(end+1,:) = [current_tilt_angle, median(kept_scores)]; %#ok<AGROW>
  end

  fprintf('    delta_defocus=%.1f A, delta_astig=%.1f A, delta_angle=%.3f rad, converged=%d\n', ...
    tilt_results.delta_defocus_tilt, tilt_results.delta_half_astigmatism, ...
    tilt_results.delta_astigmatism_angle, tilt_results.converged);

  % Clear GPU memory for this tilt group
  clear data_tiles ref_tiles;
end

%% ===== Stage F: Write refined star file =====

fprintf('Writing refined star file: %s\n', output_star_path);
write_refined_star_file(star_file_path, output_star_path, particles, ...
    refined_defocus_1, refined_defocus_2, refined_astigmatism_angle, ...
    refined_shift_x, refined_shift_y, refined_scores, refined_occupancy);

fprintf('=== CTF refinement complete ===\n');
fprintf('  Input:  %s (%d particles)\n', star_file_path, n_total_particles);
fprintf('  Output: %s\n', output_star_path);

end % EMC_ctf_refine_from_star


%% ===== Local Functions =====

function opts = parse_options(args)
% Parse name-value option pairs from varargin cell array.
  opts.defocus_search_range = 5000;
  opts.maximum_iterations = 15;
  opts.upsample_factor = 8;
  opts.upsample_window = 8;
  opts.lowpass_cutoff = 10;
  opts.warmup_iterations = 3;
  opts.astigmatism_angle_range = pi/4;
  opts.z_offset_bound_factor = 5;
  opts.n_debug_particles = 20;
  opts.skip_debug = false;

  i = 1;
  while i <= length(args)
    if ischar(args{i}) || isstring(args{i})
      key = char(args{i});
      if i + 1 <= length(args)
        val = args{i+1};
        if ischar(val) || isstring(val)
          val = str2double(val);
        end
        if isfield(opts, key)
          opts.(key) = val;
        else
          fprintf('Warning: unknown option "%s", ignoring\n', key);
        end
        i = i + 2;
      else
        fprintf('Warning: option "%s" has no value, ignoring\n', key);
        i = i + 1;
      end
    else
      i = i + 1;
    end
  end
end


function [particles, header_lines] = parse_star_file(path)
% Parse a 30-column star file into a struct array.
  fh = fopen(path, 'r');
  if fh == -1
    error('Cannot open star file: %s', path);
  end

  header_lines = {};
  data_lines = {};

  while ~feof(fh)
    line = fgetl(fh);
    if isempty(strtrim(line))
      header_lines{end+1} = line; %#ok<AGROW>
      continue;
    end
    first_char = strtrim(line);
    first_char = first_char(1);
    if first_char == '#' || first_char == '_' || ...
        startsWith(strtrim(line), 'data_') || startsWith(strtrim(line), 'loop_')
      header_lines{end+1} = line; %#ok<AGROW>
    else
      data_lines{end+1} = line; %#ok<AGROW>
    end
  end
  fclose(fh);

  n = length(data_lines);
  particles = struct('position_in_stack', cell(1,n), ...
      'psi', cell(1,n), 'theta', cell(1,n), 'phi', cell(1,n), ...
      'x_shift', cell(1,n), 'y_shift', cell(1,n), ...
      'defocus_1', cell(1,n), 'defocus_2', cell(1,n), 'defocus_angle', cell(1,n), ...
      'phase_shift', cell(1,n), 'occupancy', cell(1,n), ...
      'logp', cell(1,n), 'sigma', cell(1,n), 'score', cell(1,n), ...
      'score_change', cell(1,n), 'pixel_size', cell(1,n), ...
      'voltage_kv', cell(1,n), 'cs_mm', cell(1,n), 'amplitude_contrast', cell(1,n), ...
      'beam_tilt_x', cell(1,n), 'beam_tilt_y', cell(1,n), ...
      'image_shift_x', cell(1,n), 'image_shift_y', cell(1,n), ...
      'best_2d_class', cell(1,n), 'beam_tilt_group', cell(1,n), ...
      'particle_group', cell(1,n), 'pre_exposure', cell(1,n), ...
      'total_exposure', cell(1,n), ...
      'original_image_filename', cell(1,n), 'tilt_angle', cell(1,n));

  for i = 1:n
    tokens = strsplit(strtrim(data_lines{i}));
    if length(tokens) < 29
      error('Star file line %d has only %d tokens (expected >= 29)', i, length(tokens));
    end

    particles(i).position_in_stack = str2double(tokens{1});
    particles(i).psi = str2double(tokens{2});
    particles(i).theta = str2double(tokens{3});
    particles(i).phi = str2double(tokens{4});
    particles(i).x_shift = str2double(tokens{5});
    particles(i).y_shift = str2double(tokens{6});
    particles(i).defocus_1 = str2double(tokens{7});
    particles(i).defocus_2 = str2double(tokens{8});
    particles(i).defocus_angle = str2double(tokens{9});
    particles(i).phase_shift = str2double(tokens{10});
    particles(i).occupancy = str2double(tokens{11});
    particles(i).logp = str2double(tokens{12});
    particles(i).sigma = str2double(tokens{13});
    particles(i).score = str2double(tokens{14});
    particles(i).score_change = str2double(tokens{15});
    particles(i).pixel_size = str2double(tokens{16});
    particles(i).voltage_kv = str2double(tokens{17});
    particles(i).cs_mm = str2double(tokens{18});
    particles(i).amplitude_contrast = str2double(tokens{19});
    particles(i).beam_tilt_x = str2double(tokens{20});
    particles(i).beam_tilt_y = str2double(tokens{21});
    particles(i).image_shift_x = str2double(tokens{22});
    particles(i).image_shift_y = str2double(tokens{23});
    particles(i).best_2d_class = str2double(tokens{24});
    particles(i).beam_tilt_group = str2double(tokens{25});
    particles(i).particle_group = str2double(tokens{26});
    particles(i).pre_exposure = str2double(tokens{27});
    particles(i).total_exposure = str2double(tokens{28});
    particles(i).original_image_filename = tokens{29};

    % Column 30: tilt angle (stored as _cisTEMOriginalXPosition)
    if length(tokens) >= 30
      particles(i).tilt_angle = str2double(tokens{30});
    else
      particles(i).tilt_angle = 0;
      fprintf('Warning: particle %d missing tilt angle (col 30), defaulting to 0\n', i);
    end
  end
end


function best_permutation = run_angle_convention_debug(particles, stack_mrc, tile_size, ...
    ref_interp, ref_vol_size, n_debug_particles)
% Test 4 Euler angle permutations to determine the correct mapping.

  fprintf('\n=== Euler Angle Convention Debug ===\n');

  % Find tilt group with smallest |tilt_angle|
  all_tilt_names = {particles.original_image_filename};
  [unique_tilt_names, ~, tilt_group_indices] = unique(all_tilt_names);
  n_groups = length(unique_tilt_names);

  tilt_angles_per_group = zeros(n_groups, 1);
  for g = 1:n_groups
    members = find(tilt_group_indices == g);
    tilt_angles_per_group(g) = particles(members(1)).tilt_angle;
  end
  [~, best_group_idx] = min(abs(tilt_angles_per_group));
  best_tilt_members = find(tilt_group_indices == best_group_idx);

  % Select random subset
  n_available = length(best_tilt_members);
  n_test = min(n_debug_particles, n_available);
  rng_indices = randperm(n_available, n_test);
  test_indices = best_tilt_members(rng_indices);

  fprintf('Testing %d particles at tilt angle %.1f deg\n', n_test, ...
      tilt_angles_per_group(best_group_idx));

  % Permutation labels and transformation functions
  perm_labels = {'[psi,theta,phi]', '[-psi,-theta,-phi]', '[phi,theta,psi]', '[-phi,-theta,-psi]'};
  perm_ids = {'A', 'B', 'C', 'D'};
  scores = zeros(4, n_test);

  for pi_idx = 1:n_test
    p = particles(test_indices(pi_idx));
    slice_idx = p.position_in_stack;

    data_tile = gpuArray(single(OPEN_IMG('single', stack_mrc, ...
        [1, tile_size(1)], [1, tile_size(2)], slice_idx, 'keep')));

    % Normalize data tile for NCC
    data_tile = data_tile - mean(data_tile(:));
    data_std = std(data_tile(:));
    if data_std > 0
      data_tile = data_tile / data_std;
    end

    for perm = 1:4
      angles = apply_permutation_by_id(p.psi, p.theta, p.phi, perm_ids{perm});
      rotated_vol = ref_interp.interp3d(angles, [0,0,0], 'SPIDER', 'inv', 'C1');
      ref_projection = sum(rotated_vol, 3);
      ref_tile = center_crop_or_pad(ref_projection, tile_size);

      % Normalize reference for NCC
      ref_tile = ref_tile - mean(ref_tile(:));
      ref_std = std(ref_tile(:));
      if ref_std > 0
        ref_tile = ref_tile / ref_std;
      end

      % Normalized cross-correlation
      scores(perm, pi_idx) = gather(sum(data_tile(:) .* ref_tile(:)) / numel(data_tile));
    end
  end

  % Print results
  mean_scores = mean(scores, 2);
  std_scores = std(scores, 0, 2);
  for perm = 1:4
    fprintf('  %-25s: mean_score = %.4f (std %.4f)\n', perm_labels{perm}, mean_scores(perm), std_scores(perm));
  end

  [~, best_idx] = max(mean_scores);
  best_permutation = perm_ids{best_idx};
  fprintf('Best angle permutation: %s %s\n\n', best_permutation, perm_labels{best_idx});

  % Early exit so user can inspect diagnostic output before full refinement
  error('Early exit after angle convention debug -- review results before proceeding');
end


function angles = apply_permutation_by_id(psi, theta, phi, perm_id)
% Apply one of the 4 angle permutations identified by letter ID.
  switch perm_id
    case 'A'
      angles = [psi, theta, phi];
    case 'B'
      angles = [-psi, -theta, -phi];
    case 'C'
      angles = [phi, theta, psi];
    case 'D'
      angles = [-phi, -theta, -psi];
    otherwise
      error('Unknown permutation ID: %s', perm_id);
  end
end


function angles = apply_best_permutation(psi, theta, phi, best_permutation)
% Apply the best angle permutation determined by the debug block.
  angles = apply_permutation_by_id(psi, theta, phi, best_permutation);
end


function output = center_crop_or_pad(input, target_size)
% Center-crop or center-pad a 2D array to match target_size.
  input_size = size(input);

  if all(input_size(1:2) == target_size)
    output = input;
    return;
  end

  % Determine output origin and input origin
  output = zeros(target_size, 'like', input);
  input_origin = emc_get_origin_index(input_size(1:2));
  output_origin = emc_get_origin_index(target_size);

  % Compute overlapping region
  % In input coordinates
  in_start = max(1, input_origin - output_origin + 1);
  in_end = min(input_size(1:2), input_origin + (target_size - output_origin));

  % Corresponding output coordinates
  out_start = max(1, output_origin - input_origin + 1);
  out_end = out_start + (in_end - in_start);

  output(out_start(1):out_end(1), out_start(2):out_end(2)) = ...
      input(in_start(1):in_end(1), in_start(2):in_end(2));
end


function write_refined_star_file(input_path, output_path, particles, ...
    refined_df1, refined_df2, refined_ast_angle, ...
    refined_sx, refined_sy, refined_scores, refined_occ)
% Write refined star file by reading original and replacing refined columns.

  fh_in = fopen(input_path, 'r');
  fh_out = fopen(output_path, 'w');

  particle_idx = 0;

  while ~feof(fh_in)
    line = fgetl(fh_in);
    if line == -1
      break;
    end

    trimmed = strtrim(line);
    if isempty(trimmed)
      fprintf(fh_out, '%s\n', line);
      continue;
    end

    % Check if this is a data line (starts with a number)
    first_char = trimmed(1);
    if first_char >= '0' && first_char <= '9'
      tokens = strsplit(trimmed);
      stack_pos = str2double(tokens{1});
      if ~isnan(stack_pos) && stack_pos >= 1 && stack_pos <= length(particles)
        particle_idx = particle_idx + 1;

        % Replace columns 5-6 (shifts), 7-9 (defocus), 11 (occupancy), 14 (score)
        tokens{5} = sprintf('%9.2f', refined_sx(particle_idx));
        tokens{6} = sprintf('%9.2f', refined_sy(particle_idx));
        tokens{7} = sprintf('%8.1f', refined_df1(particle_idx));
        tokens{8} = sprintf('%8.1f', refined_df2(particle_idx));
        tokens{9} = sprintf('%7.2f', refined_ast_angle(particle_idx));
        tokens{11} = sprintf('%5i', refined_occ(particle_idx));
        tokens{14} = sprintf('%10.4f', refined_scores(particle_idx));
        fprintf(fh_out, '%s\n', strjoin(tokens, ' '));
        continue;
      end
    end

    % Header or comment line - pass through unchanged
    fprintf(fh_out, '%s\n', line);
  end

  fclose(fh_in);
  fclose(fh_out);

  fprintf('  Wrote %d refined particle records\n', particle_idx);
end
